def build_plan():
    return ['load data', 'clean data', 'summarize data', 'save report']


def load_lines(path):
    with open(path, 'r') as file:
        return file.readlines()


def clean_lines(lines):
    cleaned = []
    for line in lines:
        stripped = line.strip()
        if stripped != '':
            cleaned.append(stripped)
    return cleaned


def summarize_lines(lines):
    summary = {'count': len(lines), 'longest': ''}
    for line in lines:
        if len(line) > len(summary['longest']):
            summary['longest'] = line
    return summary


def format_report(summary):
    return f"Project Notes Report\nCount: {summary['count']}\nLongest: {summary['longest']}"


def save_report(path, text):
    with open(path, 'w') as file:
        file.write(text)


raw_lines = load_lines('data/raw_notes.txt')
cleaned_lines = clean_lines(raw_lines)
summary = summarize_lines(cleaned_lines)
report_text = format_report(summary)
save_report('data/report.txt', report_text)

with open('data/report.txt', 'r') as file:
    print(file.read())
